import requests
from urllib.parse import urlparse

def validate_url(url):
    """Validate URL against allowlist"""
    allowed_domains = ['example.com', 'example.net']  # Update with actual domains
    parsed_url = urlparse(url)
    if any(domain in parsed_url.netloc for domain in allowed_domains):
        return True
    else:
        return False

def fetch_and_display_content(url):
    """Fetch and display content of a URL"""
    if validate_url(url):
        try:
            response = requests.get(url)
            print(response.text)
        except requests.exceptions.RequestException as e:
            print(f"Error fetching URL: {e}")
    else:
        print("Invalid URL")

def main():
    url = input("Enter the URL to fetch and display content: ")
    fetch_and_display_content(url)

if __name__ == "__main__":
    main()